{"content": "     1|import { create } from 'zustand';
     2|import { persist } from 'zustand/middleware';
     3|
     4|export interface CartItem {
     5|  id: string;
     6|  name: string;
     7|  price: number;
     8|  quantity: number;
     9|  image_url?: string;
    10|  max_stock?: number;
    11|}
    12|
    13|interface CartState {
    14|  items: CartItem[];
    15|  addItem: (item: Omit<CartItem, 'quantity'>) => void;
    16|  removeItem: (id: string) => void;
    17|  updateQuantity: (id: string, quantity: number) => void;
    18|  clearCart: () => void;
    19|  totalItems: () => number;
    20|  totalPrice: () => number;
    21|}
    22|
    23|export const useCartStore = create<CartState>()(
    24|  persist(
    25|    (set, get) => ({
    26|      items: [],
    27|
    28|      addItem: (item) => {
    29|        set((state) => {
    30|          const existingItem = state.items.find((i) => i.id === item.id);
    31|          if (existingItem) {
    32|            return {
    33|              items: state.items.map((i) =>
    34|                i.id === item.id
    35|                  ? {
    36|                      ...i,
    37|                      quantity: Math.min(
    38|                        i.quantity + 1,
    39|                        i.max_stock ?? Infinity,
    40|                      ),
    41|                    }
    42|                  : i,
    43|              ),
    44|            };
    45|          }
    46|          return { items: [...state.items, { ...item, quantity: 1 }] };
    47|        });
    48|      },
    49|
    50|      removeItem: (id) => {
    51|        set((state) => ({
    52|          items: state.items.filter((i) => i.id !== id),
    53|        }));
    54|      },
    55|
    56|      updateQuantity: (id, quantity) => {
    57|        set((state) => ({
    58|          items:
    59|            quantity <= 0
    60|              ? state.items.filter((i) => i.id !== id)
    61|              : state.items.map((i) =>
    62|                  i.id === id
    63|                    ? { ...i, quantity: Math.min(quantity, i.max_stock ?? Infinity) }
    64|                    : i,
    65|                ),
    66|        }));
    67|      },
    68|
    69|      clearCart: () => set({ items: [] }),
    70|
    71|      totalItems: () => {
    72|        return get().items.reduce((total, item) => total + item.quantity, 0);
    73|      },
    74|
    75|      totalPrice: () => {
    76|        return get().items.reduce(
    77|          (total, item) => total + item.price * item.quantity,
    78|          0,
    79|        );
    80|      },
    81|    }),
    82|    {
    83|      name: 'fun4me-cart',
    84|    },
    85|  ),
    86|);
