{"content": "'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Button } from '@/components/ui/button';
import { CartDrawer } from '@/components/store/cart-drawer';
import { SearchAutocomplete } from '@/components/store/search-autocomplete';
import { generateWhatsAppLink } from '@/lib/utils/whatsapp';
import { Menu, X, ChevronDown, User, Calendar } from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import type { ExtendedCategory, KinkCategory } from '@/types/database';

export function Header() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [categoriesOpen, setCategoriesOpen] = useState(false);
  const [categories, setCategories] = useState<ExtendedCategory[]>([]);
  const [kinks, setKinks] = useState<KinkCategory[]>([]);
  const [user, setUser] = useState<any>(null);

  useEffect(() => {
    const supabase = createClient();
    const sb = supabase as any;
    supabase.from('categories').select('*').eq('is_active', true).order('sort_order').then(({ data }) => {
      if (data) setCategories(data as unknown as ExtendedCategory[]);
    });
    sb.from('kink_categories').select('*').order('sort_order').then(({ data }: { data: KinkCategory[] | null }) => {
      if (data) setKinks(data);
    });
    supabase.auth.getUser().then(({ data }) => {
      if (data?.user) setUser(data.user);
    });
  }, []);

  const whatsappLink = generateWhatsAppLink('¡Hola! Me interesa saber más sobre Fun4Me Store.');

  return (
    <header className="sticky top-0 z-40 w-full border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
      <div className="container mx-auto flex h-14 items-center justify-between gap-4 px-4">
        {/* Logo */}
        <Link href="/" className="flex shrink-0 items-center gap-2">
          <span className="bg-gradient-to-r from-rose-500 to-purple-600 bg-clip-text text-xl font-bold text-transparent">
            Fun4Me
          </span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden items-center gap-1 md:flex">
          <Link href="/"><Button variant="ghost" size="sm">Tienda</Button></Link>
          <div className="relative">
            <Button variant="ghost" size="sm" onClick={() => setCategoriesOpen(!categoriesOpen)} className="gap-1">
              Categorías <ChevronDown className="h-3 w-3" />
            </Button>
            {categoriesOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setCategoriesOpen(false)} />
                <div className="absolute left-0 top-full z-20 mt-1 w-56 rounded-lg border bg-popover p-2 shadow-lg">
                  {categories.map((cat) => (
                    <Link key={cat.id} href={`/categoria/${cat.slug}`} onClick={() => setCategoriesOpen(false)}
                      className="flex items-center gap-2 rounded-md px-3 py-2 text-sm hover:bg-muted">{cat.name}</Link>
                  ))}
                </div>
              </>
            )}
          </div>
          <Link href="/#kinks"><Button variant="ghost" size="sm">Por Kink</Button></Link>
          <Link href="/ofertas"><Button variant="ghost" size="sm">Ofertas</Button></Link>
          <Link href="/eventos"><Button variant="ghost" size="sm" className="gap-1"><Calendar className="h-4 w-4" />Eventos</Button></Link>
        </nav>

        {/* Search Bar */}
        <SearchAutocomplete className="hidden flex-1 max-w-xs md:block" />

        {/* Right Icons */}
        <div className="flex items-center gap-3">
          {user ? (
            <Link href="/cuenta" className="hidden sm:flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground">
              <User className="h-5 w-5" />
            </Link>
          ) : (
            <Link href="/iniciar-sesion" className="hidden sm:block">
              <Button variant="ghost" size="sm">Ingresar</Button>
            </Link>
          )}
          <a href={whatsappLink} target="_blank" rel="noopener noreferrer"
